@prefix ada: <https://ada.astromat.org/metadata/> .
@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:TabularTextDataSet,
                        ada:tabularData ;
                    cdi:isDelimited true ] ;
            sh:resultMessage "Tabular data must have a componentType." ;
            sh:resultPath ada:componentType ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "Tabular data must have a componentType." ;
                    sh:minCount 1 ;
                    sh:path ada:componentType ] ] .

@prefix sh: <http://www.w3.org/ns/shacl#> .
